[ExtensionOf(formStr(InventJournalTransfer))]
public final class InventJournalTransfer_ETGSPAIN_Form_Extension
{
}

Method.Source:
/// <summary>
/// Extension of the <c>init</c> method for the ETGSPAIN model.
/// </summary>
/// <remarks>This code is used to show/hide features in Spanish companies.</remarks>
public void init()
{
    next init();
    NoYesId currentCompanyIsSpanishCompany  = Global::CurrentCompanyIsSpanishCompany();

    this.design().controlName(formControlStr(InventJournalTransfer, ETGSPAINInventJournalLineImportLog)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(InventJournalTransfer, ETGSPAINInventJournalLineImport)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(InventJournalTransfer, ETGSPAINSalesPackingSlipImport)).visible(currentCompanyIsSpanishCompany);

    this.design().controlName(formControlStr(InventJournalTransfer, ETGSPAINInventJournalTrans_ETGSPAINInventAppliedQty)).visible(currentCompanyIsSpanishCompany);

}
